import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { SeedService } from '../../data/seed.service';
import { Project } from '../../data/models';

type StageFilter = Project['stage'] | 'all';

@Component({
  selector: 'app-projects',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './projects.component.html',
  styleUrl: './projects.component.css',
})
export class ProjectsComponent {
  // Weighting factors used to compute a stage-weighted pipeline value.
  private readonly stageWeight: Record<Project['stage'], number> = {
    quoting: 0.2,
    submitted: 0.4,
    negotiation: 0.6,
    awarded: 0.9,
    closed: 1.0,
  };

  readonly stages: Project['stage'][] = ['quoting', 'submitted', 'negotiation', 'awarded', 'closed'];
  readonly filter = signal<StageFilter>('all');

  visibleProjects = computed(() => {
    const f = this.filter();
    const list = this.seed.projects();
    return f === 'all' ? list : list.filter((p) => p.stage === f);
  });

  totalPipeline = computed(() =>
    this.seed.projects().reduce((sum, p) => sum + p.value, 0),
  );

  weightedPipeline = computed(() =>
    this.seed.projects().reduce((sum, p) => sum + p.value * this.stageWeight[p.stage], 0),
  );

  countByStage = computed(() => {
    const counts: Record<string, number> = {};
    for (const s of this.stages) counts[s] = 0;
    for (const p of this.seed.projects()) counts[p.stage] = (counts[p.stage] ?? 0) + 1;
    return counts;
  });

  setFilter(f: StageFilter): void {
    this.filter.set(f);
  }

  stageBadge(stage: Project['stage']): string {
    switch (stage) {
      case 'quoting': return 'badge-info';
      case 'submitted': return 'badge-warning';
      case 'negotiation': return 'badge-warning';
      case 'awarded': return 'badge-success';
      case 'closed': return 'badge-neutral';
      default: return 'badge-neutral';
    }
  }

  constructor(public seed: SeedService) {}
}
